from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from itsdangerous import URLSafeTimedSerializer
import os
import smtplib
import random
import string

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
app.config['SECRET_KEY'] = os.urandom(24)
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    reset_token = db.Column(db.String(200), nullable=True)

db.create_all()

def generate_token(email):
    serializer = URLSafeTimedSerializer(app.config['SECRET_KEY'])
    return serializer.dumps(email, salt='password-reset-salt')

def send_email(to_email, token):
    reset_link = f'http://localhost:5000/reset_password/{token}'
    with smtplib.SMTP('smtp.example.com', 587) as server:
        server.starttls()
        server.login('your_email@example.com', 'your_password')
        server.sendmail('your_email@example.com', to_email, f'Subject: Password Reset\n\nClick the link to reset your password: {reset_link}')

@app.route('/request_reset', methods=['POST'])
def request_reset():
    email = request.json.get('email')
    user = User.query.filter_by(email=email).first()
    if user:
        token = generate_token(email)
        user.reset_token = token
        db.session.commit()
        send_email(email, token)
    return jsonify({'message': 'If the email is registered, a reset link has been sent.'}), 200

@app.route('/reset_password/<token>', methods=['POST'])
def reset_password(token):
    serializer = URLSafeTimedSerializer(app.config['SECRET_KEY'])
    try:
        email = serializer.loads(token, salt='password-reset-salt', max_age=3600)
    except Exception:
        return jsonify({'message': 'Invalid or expired token.'}), 400
    
    new_password = request.json.get('new_password')
    user = User.query.filter_by(email=email).first()
    if user:
        # Here you would hash the new password before saving
        user.reset_token = None  # Clear the token after use
        db.session.commit()
        return jsonify({'message': 'Password has been reset.'}), 200
    return jsonify({'message': 'User not found.'}), 404

if __name__ == '__main__':
    app.run(debug=True)